import React from "react";
import { Link } from "react-router-dom";

const CourseCard = ({ course }) => {
  const { _id, title, description, instructor, duration, category, level, thumbnail, rating, enrolledCount } = course;

  const categoryColors = {
    "Programming Language": { bg: "rgba(96,165,250,0.12)", color: "#93c5fd" },
    "Web Development": { bg: "rgba(45,212,191,0.12)", color: "#5eead4" },
    "Backend Development": { bg: "rgba(251,191,36,0.12)", color: "#fbbf24" },
    "Data Science": { bg: "rgba(244,114,182,0.12)", color: "#f9a8d4" },
  };

  const levelColors = {
    Beginner: { bg: "rgba(45,212,191,0.12)", color: "#5eead4" },
    Intermediate: { bg: "rgba(251,191,36,0.12)", color: "#fbbf24" },
    Advanced: { bg: "rgba(251,113,133,0.12)", color: "#fb7185" },
  };

  const catStyle = categoryColors[category] || categoryColors["Web Development"];
  const lvlStyle = levelColors[level] || levelColors.Beginner;
  const safeRating = rating || 4.5;

  return (
    <div
      className="card h-100 border-0"
      style={{ borderRadius: 22, overflow: "hidden", transition: "transform 180ms ease, box-shadow 180ms ease, border-color 180ms ease" }}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = "translateY(-4px)";
        e.currentTarget.style.borderColor = "rgba(96,165,250,0.34)";
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = "translateY(0)";
        e.currentTarget.style.borderColor = "var(--border)";
      }}
    >
      <div style={{ position: "relative", height: 220, overflow: "hidden" }}>
        <img
          src={thumbnail || "https://images.unsplash.com/photo-1516116216624-53e697fedbea?w=800"}
          alt={title}
          className="w-100 h-100"
          style={{ objectFit: "cover" }}
          onError={(e) => {
            e.target.src = "https://images.unsplash.com/photo-1516116216624-53e697fedbea?w=800";
          }}
        />
        <div style={{ position: "absolute", inset: 0, background: "linear-gradient(180deg, transparent 30%, rgba(8,16,31,0.88) 100%)" }} />
        <div className="position-absolute top-0 start-0 end-0 p-3 d-flex align-items-start justify-content-between gap-2">
          <span
            className="badge"
            style={{
              background: lvlStyle.bg,
              color: lvlStyle.color,
              borderRadius: 999,
              padding: "8px 12px",
              fontWeight: 700,
              border: `1px solid ${lvlStyle.color}33`,
            }}
          >
            {level}
          </span>
          <div
            className="px-3 py-2"
            style={{
              borderRadius: 999,
              background: "rgba(8,16,31,0.72)",
              border: "1px solid rgba(148,163,184,0.16)",
              color: "var(--text)",
              fontSize: "0.8rem",
              fontWeight: 700,
            }}
          >
            {safeRating.toFixed(1)}
          </div>
        </div>
      </div>

      <div className="card-body d-flex flex-column gap-3 p-4">
        <div className="d-flex align-items-center justify-content-between gap-3">
          <span
            style={{
              display: "inline-flex",
              alignItems: "center",
              padding: "7px 12px",
              borderRadius: 999,
              fontSize: "0.72rem",
              fontWeight: 800,
              textTransform: "uppercase",
              letterSpacing: "0.08em",
              background: catStyle.bg,
              color: catStyle.color,
            }}
          >
            {category}
          </span>
          <span style={{ color: "var(--text-muted)", fontSize: "0.82rem", fontWeight: 700 }}>
            {enrolledCount?.toLocaleString() || 0} enrolled
          </span>
        </div>

        <div>
          <h5 className="card-title mb-2 fw-bold" style={{ color: "var(--text)", fontSize: "1.08rem", lineHeight: 1.35 }}>
            {title}
          </h5>
          <p className="card-text mb-0" style={{ color: "var(--text-secondary)", lineHeight: 1.7 }}>
            {description?.length > 118 ? `${description.slice(0, 118)}...` : description}
          </p>
        </div>

        <div className="d-flex flex-wrap gap-3" style={{ color: "var(--text-muted)", fontSize: "0.86rem" }}>
          <span className="d-inline-flex align-items-center gap-2">
            <i className="bi bi-person" style={{ color: "var(--primary)" }} />
            {instructor}
          </span>
          <span className="d-inline-flex align-items-center gap-2">
            <i className="bi bi-clock-history" style={{ color: "var(--accent)" }} />
            {duration}
          </span>
        </div>

        <div className="d-flex align-items-center justify-content-between gap-3 mt-auto pt-3" style={{ borderTop: "1px solid var(--border)" }}>
          <div className="d-flex align-items-center gap-2" style={{ color: "var(--text-secondary)" }}>
            <i className="bi bi-star-fill" style={{ color: "var(--warning)" }} />
            <span className="fw-bold" style={{ color: "var(--text)" }}>
              {safeRating.toFixed(1)}
            </span>
            <span style={{ color: "var(--text-muted)" }}>Course rating</span>
          </div>
          <Link to={`/course/${_id}`} className="btn btn-primary-custom btn-sm px-3 py-2">
            View Course
          </Link>
        </div>
      </div>
    </div>
  );
};

export default CourseCard;
